let _current: Record<string, string> = translations['en'];

export function setLocale(locale: 'en' | 'de' | Record<string, string>): void {
  if (typeof locale === 'string') {
    _current = translations[locale] ?? translations['en'];
  } else {
    _current = { ...translations['en'], ...locale };
  }
}

export function t(key: string): string {
  return _current[key] ?? key;
}
